trait CredentialManager {
  def getCredentialsProvider(config: AwsConfig): AwsCredentialsProvider
}

class DefaultCredentialManager extends CredentialManager {

  override def getCredentialsProvider(config: AwsConfig): AwsCredentialsProvider = {
    config.credentialSource match {
      case EnvironmentVariables =>
        validateEnvironmentVariables()
        EnvironmentVariableCredentialsProvider.create()

      case DefaultChain =>
        DefaultCredentialsProvider.create()

      case SecretsManager(secretName) =>
        resolveFromSecretsManager(secretName, config.region)

      case StaticCreds(accessKey, secretKey) =>
        StaticCredentialsProvider.create(
          AwsBasicCredentials.create(accessKey, secretKey)
        )
    }
  }

  private def validateEnvironmentVariables(): Unit = {
    val requiredVars = List("AWS_ACCESS_KEY_ID", "AWS_SECRET_ACCESS_KEY")
    val missing = requiredVars.filter(v => Option(System.getenv(v)).isEmpty)
    if (missing.nonEmpty) {
      throw new IllegalStateException(
        s"Missing required environment variables: ${missing.mkString(", ")}"
      )
    }
  }

  private def resolveFromSecretsManager(secretName: String, region: Region): AwsCredentialsProvider = {
    val smClient = SecretsManagerClient.builder()
      .region(region)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    try {
      val request = GetSecretValueRequest.builder()
        .secretId(secretName)
        .build()

      val response = smClient.getSecretValue(request)
      val secretString = response.secretString()

      val parsed = parseSecretJson(secretString)
      val accessKey = parsed.getOrElse("accessKey",
        throw new IllegalStateException("Secret missing 'accessKey' field"))
      val secretKey = parsed.getOrElse("secretKey",
        throw new IllegalStateException("Secret missing 'secretKey' field"))

      StaticCredentialsProvider.create(
        AwsBasicCredentials.create(accessKey, secretKey)
      )
    } finally {
      smClient.close()
    }
  }

  private def parseSecretJson(json: String): Map[String, String] = {
    val cleaned = json.trim.stripPrefix("{").stripSuffix("}")
    cleaned.split(",").map { pair =>
      val parts = pair.split(":", 2)
      val key = parts(0).trim.stripPrefix("\"").stripSuffix("\"")
      val value = parts(1).trim.stripPrefix("\"").stripSuffix("\"")
      key -> value
    }.toMap
  }
}

