class S3Service(config: AwsConfig, credentialManager: CredentialManager) extends AwsServiceClient {

  private val s3Client: S3Client = S3Client.builder()
    .region(config.region)
    .credentialsProvider(credentialManager.getCredentialsProvider(config))
    .build()

  def listBuckets(): Try[List[String]] = Try {
    s3Client.listBuckets().buckets().asScala.map(_.name()).toList
  }

  def createBucket(bucketName: String): Try[String] = Try {
    val request = CreateBucketRequest.builder()
      .bucket(bucketName)
      .build()
    s3Client.createBucket(request)
    s"Bucket '$bucketName' created successfully"
  }

  def listObjects(bucketName: String, prefix: Option[String] = None): Try[List[String]] = Try {
    val requestBuilder = ListObjectsV2Request.builder().bucket(bucketName)
    prefix.foreach(p => requestBuilder.prefix(p))
    val response = s3Client.listObjectsV2(requestBuilder.build())
    response.contents().asScala.map(_.key()).toList
  }

  def putObject(bucketName: String, key: String, content: String): Try[String] = Try {
    val request = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    s3Client.putObject(request,
      software.amazon.awssdk.core.sync.RequestBody.fromString(content))
    s"Object '$key' uploaded to bucket '$bucketName'"
  }

  def deleteObject(bucketName: String, key: String): Try[String] = Try {
    val request = DeleteObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    s3Client.deleteObject(request)
    s"Object '$key' deleted from bucket '$bucketName'"
  }

  override def close(): Unit = s3Client.close()
}

class SqsService(config: AwsConfig, credentialManager: CredentialManager) extends AwsServiceClient {

  private val sqsClient: SqsClient = SqsClient.builder()
    .region(config.region)
    .credentialsProvider(credentialManager.getCredentialsProvider(config))
    .build()

  def sendMessage(queueUrl: String, messageBody: String): Try[String] = Try {
    val request = SendMessageRequest.builder()
      .queueUrl(queueUrl)
      .messageBody(messageBody)
      .build()
    val response = sqsClient.sendMessage(request)
    response.messageId()
  }

  def receiveMessages(queueUrl: String, maxMessages: Int = 10): Try[List[(String, String)]] = Try {
    val request = ReceiveMessageRequest.builder()
      .queueUrl(queueUrl)
      .maxNumberOfMessages(maxMessages)
      .build()
    val response = sqsClient.receiveMessage(request)
    response.messages().asScala.map(m => (m.messageId(), m.body())).toList
  }

  override def close(): Unit = sqsClient.close()
}

class DynamoDbService(config: AwsConfig, credentialManager: CredentialManager) extends AwsServiceClient {

  private val dynamoClient: DynamoDbClient = DynamoDbClient.builder()
    .region(config.region)
    .credentialsProvider(credentialManager.getCredentialsProvider(config))
    .build()

  def putItem(tableName: String, item: Map[String, String]): Try[String] = Try {
    val attributes = item.map { case (k, v) =>
      k -> AttributeValue.builder().s(v).build()
    }.asJava

    val request = PutItemRequest.builder()
      .tableName(tableName)
      .item(attributes)
      .build()

    dynamoClient.putItem(request)
    s"Item inserted into table '$tableName'"
  }

  def getItem(tableName: String, key: Map[String, String]): Try[Map[String, String]] = Try {
    val keyAttributes = key.map { case (k, v) =>
      k -> AttributeValue.builder().s(v).build()
    }.asJava

    val request = GetItemRequest.builder()
      .tableName(tableName)
      .key(keyAttributes)
      .build()

    val response = dynamoClient.getItem(request)
    response.item().asScala.map { case (k, v) => k -> v.s() }.toMap
  }

  override def close(): Unit = dynamoClient.close()
}

