    new DynamoDbService(config, credentialManager)
}

object AwsServiceApp {

  def main(args: Array[String]): Unit = {

    val config = AwsConfig(
      region = Region.of(
        Option(System.getenv("AWS_REGION")).getOrElse("us-east-1")
      ),
      credentialSource = determineCredentialSource()
    )

    val factory = new AwsServiceFactory()

    println("=== AWS Service Integration Demo ===")
    println(s"Region: ${config.region}")
    println(s"Credential Source: ${config.credentialSource}")

    val s3Service = factory.createS3Service(config)
    try {
      println("\n--- S3 Operations ---")
      s3Service.listBuckets() match {
        case Success(buckets) =>
          println(s"Found ${buckets.size} buckets:")
          buckets.foreach(b => println(s"  - $b"))
        case Failure(ex) =>
          println(s"Failed to list buckets: ${ex.getMessage}")
      }
    } finally {
      s3Service.close()
    }

    val dynamoService = factory.createDynamoDbService(config)
    try {
      println("\n--- DynamoDB Operations ---")
      val tableName = Option(System.getenv("DYNAMO_TABLE")).getOrElse("test-table")

      dynamoService.putItem(tableName, Map(
        "id" -> "item-001",
        "name" -> "Test Item",
        "status" -> "active"
      )) match {
        case Success(msg) => println(msg)
        case Failure(ex) => println(s"Failed to put item: ${ex.getMessage}")
      }

      dynamoService.getItem(tableName, Map("id" -> "item-001")) match {
        case Success(item) =>
          println(s"Retrieved item: $item")
        case Failure(ex) =>
          println(s"Failed to get item: ${ex.getMessage}")
      }
    } finally {
      dynamoService.close()
    }

    val sqsService = factory.createSqsService(config)
    try {
      println("\n--- SQS Operations ---")
      val queueUrl = Option(System.getenv("SQS_QUEUE_URL")).getOrElse("")
      if (queueUrl.nonEmpty) {
        sqsService.sendMessage(queueUrl, """{"event":"test","timestamp":"2024-01-01"}""") match {
          case Success(messageId) => println(s"Message sent with ID: $messageId")
          case Failure(ex) => println(s"Failed to send message: ${ex.getMessage}")
        }

        sqsService.receiveMessages(queueUrl, maxMessages = 5) match {
          case Success(messages) =>
            println(s"Received ${messages.size} messages:")
            messages.foreach { case (id, body) =>
              println(s"  [$id]: $body")
            }
          case Failure(ex) =>
            println(s"Failed to receive messages: ${ex.getMessage}")
        }
      } else {
        println("SQS_QUEUE_URL not set, skipping SQS operations")
      }
    } finally {
      sqsService.close()
    }

    println("\n=== Demo Complete ===")
  }

  private def determineCredentialSource(): CredentialSource = {
    val source = Option(System.getenv("AWS_CREDENTIAL_SOURCE")).getOrElse("default")
    source.toLowerCase match {
      case "environment" => EnvironmentVariables
      case "secretsmanager" =>
        val secretName = Option(System.getenv("AWS_SECRET_NAME"))
          .getOrElse(throw new IllegalStateException(
            "AWS_SECRET_NAME must be set when using SecretsManager credential source"
          ))
        SecretsManager(secretName)
      case "default" => DefaultChain
      case other =>
        println(s"Unknown credential source '$other', falling back to default chain")
        DefaultChain
    }
  }
